package concrete.goonie.chart.api.data; import concrete.goonie.chart.api.model.Timeframe; public abstract class ValueDataSet extends DataSet { private final double[] xValues; private final double[] yValues; protected ValueDataSet(String name, DataSetType type, double[] xValues, double[] yValues, Timeframe... timeframes){ super(name,type,timeframes); this.xValues=xValues; this.yValues=yValues; } public final int size(){ return Math.min(xValues.length,yValues.length); } public final double xAt(int index){ return xValues[index]; } public final double yAt(int index){ return yValues[index]; } }